/**
 * WeTime Video Resolver
 *
 * WeTime share URLs (`wetime.io/preview/ID`) don't expose a direct media URL
 * via the share token — the ID maps to a CloudFront-hosted MP4 only after the
 * preview page is rendered. This server function fetches the preview HTML and
 * extracts the `<source src="...mp4">` so we can play it in a native <video>
 * element instead of iframing the full WeTime chrome.
 */

import { createServerFn } from "@tanstack/react-start"
import { z } from "zod"
import { getSessionFromCookie } from "@/utils/auth"

const inputSchema = z.object({
  videoId: z
    .string()
    .min(1)
    .max(64)
    .regex(/^[a-zA-Z0-9_-]+$/, "Invalid WeTime video id"),
})

export const resolveWeTimeVideoUrlFn = createServerFn({ method: "GET" })
  .inputValidator((input: unknown) => inputSchema.parse(input))
  .handler(async ({ data }): Promise<{ videoUrl: string }> => {
    const session = await getSessionFromCookie()
    if (!session?.userId) {
      throw new Error("Not authenticated")
    }

    const previewUrl = `https://wetime.io/preview/${data.videoId}`
    const res = await fetch(previewUrl, {
      headers: {
        "User-Agent":
          "Mozilla/5.0 (compatible; WodsmithBot/1.0; +https://wodsmith.com)",
      },
    })
    if (!res.ok) {
      throw new Error(`WeTime preview fetch failed: ${res.status}`)
    }

    const html = await res.text()
    const match = html.match(/<source\s+src="([^"]+\.mp4[^"]*)"/i)
    if (!match?.[1]) {
      throw new Error("Could not locate video source in WeTime preview")
    }

    return { videoUrl: match[1] }
  })

/**
 * Video URL Validation Schema
 *
 * Validates video URLs for online competition submissions.
 * Supports YouTube, Vimeo, and WodProof URL formats with video ID extraction.
 */

import { z } from "zod"

/**
 * Supported video platforms
 */
export const VIDEO_PLATFORMS = [
  "youtube",
  "vimeo",
  "wodproof",
  "wetime",
] as const
export type VideoPlatform = (typeof VIDEO_PLATFORMS)[number]

/**
 * Result of parsing a video URL
 */
export interface ParsedVideoUrl {
  platform: VideoPlatform
  videoId: string
  originalUrl: string
  embedUrl: string
  thumbnailUrl: string
  /** Privacy hash for unlisted Vimeo videos */
  privacyHash?: string
  /** Whether this platform supports inline embedding (iframe/player) */
  supportsEmbed: boolean
}

/**
 * YouTube URL patterns:
 * - youtube.com/watch?v=VIDEO_ID
 * - youtube.com/watch?v=VIDEO_ID&t=123s (with timestamp)
 * - youtu.be/VIDEO_ID
 * - youtu.be/VIDEO_ID?t=123 (with timestamp)
 * - youtube.com/embed/VIDEO_ID
 * - youtube.com/v/VIDEO_ID
 * - youtube.com/shorts/VIDEO_ID
 * - m.youtube.com/watch?v=VIDEO_ID (mobile)
 * - www.youtube.com/watch?v=VIDEO_ID
 */
const YOUTUBE_PATTERNS = [
  // Standard watch URL
  /^(?:https?:\/\/)?(?:www\.|m\.)?youtube\.com\/watch\?(?:.*&)?v=([a-zA-Z0-9_-]{11})(?:&.*)?$/,
  // Short URL
  /^(?:https?:\/\/)?youtu\.be\/([a-zA-Z0-9_-]{11})(?:\?.*)?$/,
  // Embed URL
  /^(?:https?:\/\/)?(?:www\.)?youtube\.com\/embed\/([a-zA-Z0-9_-]{11})(?:\?.*)?$/,
  // Old-style /v/ URL
  /^(?:https?:\/\/)?(?:www\.)?youtube\.com\/v\/([a-zA-Z0-9_-]{11})(?:\?.*)?$/,
  // Shorts URL
  /^(?:https?:\/\/)?(?:www\.)?youtube\.com\/shorts\/([a-zA-Z0-9_-]{11})(?:\?.*)?$/,
] as const

/**
 * Vimeo URL patterns:
 * - vimeo.com/VIDEO_ID
 * - vimeo.com/VIDEO_ID?share=copy (with params)
 * - vimeo.com/VIDEO_ID/HASH (unlisted videos with privacy hash)
 * - player.vimeo.com/video/VIDEO_ID
 * - player.vimeo.com/video/VIDEO_ID?h=HASH (unlisted embed)
 * - www.vimeo.com/VIDEO_ID
 * - vimeo.com/channels/CHANNEL/VIDEO_ID
 * - vimeo.com/groups/GROUP/videos/VIDEO_ID
 */
const VIMEO_PATTERNS = [
  // Unlisted URL with privacy hash (must be before standard pattern)
  /^(?:https?:\/\/)?(?:www\.)?vimeo\.com\/(\d+)\/([a-zA-Z0-9]+)(?:\?.*)?$/,
  // Standard URL
  /^(?:https?:\/\/)?(?:www\.)?vimeo\.com\/(\d+)(?:\?.*)?$/,
  // Player embed URL with hash
  /^(?:https?:\/\/)?player\.vimeo\.com\/video\/(\d+)\?(?:.*&)?h=([a-zA-Z0-9]+)(?:&.*)?$/,
  // Player embed URL without hash
  /^(?:https?:\/\/)?player\.vimeo\.com\/video\/(\d+)(?:\?.*)?$/,
  // Channel video URL
  /^(?:https?:\/\/)?(?:www\.)?vimeo\.com\/channels\/[^/]+\/(\d+)(?:\?.*)?$/,
  // Group video URL
  /^(?:https?:\/\/)?(?:www\.)?vimeo\.com\/groups\/[^/]+\/videos\/(\d+)(?:\?.*)?$/,
] as const

/**
 * WodProof URL patterns:
 *
 * WodProof videos are shared as cloud links from the mobile app.
 * The cloud URL format is: https://wodproofapp.com/cloud/?v=VIDEO_ID
 * The actual MP4 is hosted at: https://s3.us-east-1.amazonaws.com/wodproof-cloud/VIDEO_ID.mp4
 *
 * We extract the video ID from the `v` query parameter and construct
 * the S3 URL for direct <video> element playback.
 *
 * Known domain patterns:
 * - wodproofapp.com/cloud/?v=ID (cloud share links)
 * - wodproofapp.com/* (other paths)
 * - *.wodproof.com/* (any subdomain)
 */
const WODPROOF_PATTERNS = [
  // wodproofapp.com with any path (main domain, www only)
  /^(?:https?:\/\/)?(?:www\.)?wodproofapp\.com\/(.+)$/,
  // wodproof.com (alternate domain) with path
  /^(?:https?:\/\/)?(?:www\.)?wodproof\.com\/(.+)$/,
] as const

/**
 * WeTime URL patterns:
 *
 * WeTime is a competition timing/video-proof service. Shareable links look like
 * https://wetime.io/preview/ID where ID is a short alphanumeric token.
 * The preview page itself embeds a <video> with a CloudFront-hosted MP4, but
 * the ID → MP4 mapping requires fetching the page — we iframe the preview URL
 * directly instead. CSP `frame-ancestors 'self' *` permits cross-origin framing.
 */
const WETIME_PATTERNS = [
  // Canonical share URL: wetime.io/preview/ID
  /^(?:https?:\/\/)?(?:www\.)?wetime\.io\/preview\/([a-zA-Z0-9_-]+)(?:[/?#].*)?$/,
] as const

/**
 * Extract the video ID from a WodProof URL.
 * For cloud URLs (wodproofapp.com/cloud/?v=ID), extracts the `v` query parameter.
 * For other WodProof URLs, falls back to the path as an identifier.
 */
function extractWodProofId(url: string): string | null {
  for (const pattern of WODPROOF_PATTERNS) {
    const match = url.match(pattern)
    if (match) {
      // Try to extract `v` query parameter from cloud URLs
      try {
        const parsed = new URL(
          url.startsWith("http") ? url : `https://${url}`,
        )
        const videoId = parsed.searchParams.get("v")
        if (videoId) {
          return videoId
        }
      } catch {
        // Fall through to path-based extraction
      }

      // Use the last captured group (the path) as the ID
      const path = match[match.length - 1]
      if (path && path.length > 0) {
        return path.replace(/[?#].*$/, "") // strip query/hash
      }
    }
  }
  return null
}

/**
 * Construct the direct S3 MP4 URL for a WodProof video.
 * WodProof stores videos at: https://s3.us-east-1.amazonaws.com/wodproof-cloud/{videoId}.mp4
 */
export function getWodProofVideoUrl(videoId: string): string {
  return `https://s3.us-east-1.amazonaws.com/wodproof-cloud/${videoId}.mp4`
}

/**
 * Extract the video ID from a WeTime preview URL.
 */
function extractWeTimeId(url: string): string | null {
  for (const pattern of WETIME_PATTERNS) {
    const match = url.match(pattern)
    if (match?.[1]) {
      return match[1]
    }
  }
  return null
}

/**
 * Extract video ID from YouTube URL
 */
function extractYouTubeId(url: string): string | null {
  for (const pattern of YOUTUBE_PATTERNS) {
    const match = url.match(pattern)
    if (match?.[1]) {
      return match[1]
    }
  }
  return null
}

/**
 * Extract video ID and optional privacy hash from Vimeo URL
 */
function extractVimeoId(url: string): { id: string; hash?: string } | null {
  for (const pattern of VIMEO_PATTERNS) {
    const match = url.match(pattern)
    if (match?.[1]) {
      return {
        id: match[1],
        hash: match[2] || undefined,
      }
    }
  }
  return null
}

/**
 * Parse a video URL and extract platform and video ID
 * Returns null if URL is not from a supported platform
 */
export function parseVideoUrl(url: string): ParsedVideoUrl | null {
  const trimmedUrl = url.trim()

  // Try YouTube first
  const youtubeId = extractYouTubeId(trimmedUrl)
  if (youtubeId) {
    return {
      platform: "youtube",
      videoId: youtubeId,
      originalUrl: trimmedUrl,
      embedUrl: `https://www.youtube.com/embed/${youtubeId}`,
      thumbnailUrl: `https://img.youtube.com/vi/${youtubeId}/maxresdefault.jpg`,
      supportsEmbed: true,
    }
  }

  // Try Vimeo
  const vimeoResult = extractVimeoId(trimmedUrl)
  if (vimeoResult) {
    // For unlisted videos, include the privacy hash in the embed URL
    const embedUrl = vimeoResult.hash
      ? `https://player.vimeo.com/video/${vimeoResult.id}?h=${vimeoResult.hash}`
      : `https://player.vimeo.com/video/${vimeoResult.id}`
    return {
      platform: "vimeo",
      videoId: vimeoResult.id,
      originalUrl: trimmedUrl,
      embedUrl,
      // Vimeo thumbnails require API access, use placeholder
      thumbnailUrl: `https://vumbnail.com/${vimeoResult.id}.jpg`,
      privacyHash: vimeoResult.hash,
      supportsEmbed: true,
    }
  }

  // Try WodProof
  const wodproofId = extractWodProofId(trimmedUrl)
  if (wodproofId) {
    return {
      platform: "wodproof",
      videoId: wodproofId,
      originalUrl: trimmedUrl,
      embedUrl: getWodProofVideoUrl(wodproofId),
      thumbnailUrl: "",
      supportsEmbed: true,
    }
  }

  // Try WeTime
  const wetimeId = extractWeTimeId(trimmedUrl)
  if (wetimeId) {
    return {
      platform: "wetime",
      videoId: wetimeId,
      originalUrl: trimmedUrl,
      embedUrl: `https://wetime.io/preview/${wetimeId}`,
      thumbnailUrl: "",
      supportsEmbed: true,
    }
  }

  return null
}

/**
 * Check if a URL is from a supported video platform
 */
export function isSupportedVideoUrl(url: string): boolean {
  return parseVideoUrl(url) !== null
}

/**
 * Get a human-readable list of supported platforms
 */
export function getSupportedPlatformsText(): string {
  return "YouTube, Vimeo, WodProof, or WeTime"
}

/**
 * Error messages for video URL validation
 */
export const VIDEO_URL_ERRORS = {
  INVALID_URL: "Please enter a valid URL",
  UNSUPPORTED_PLATFORM: `Please use a video from ${getSupportedPlatformsText()}`,
  EMPTY_URL: "Video URL is required",
  EXTRACT_FAILED:
    "Could not extract video ID from URL. Please check the URL format.",
} as const

/**
 * Zod schema for validating video URLs
 *
 * Usage:
 * ```typescript
 * const result = videoUrlSchema.safeParse(url)
 * if (result.success) {
 *   console.log(result.data) // ParsedVideoUrl
 * }
 * ```
 */
export const videoUrlSchema = z
  .string()
  .min(1, VIDEO_URL_ERRORS.EMPTY_URL)
  .url(VIDEO_URL_ERRORS.INVALID_URL)
  .transform((url, ctx) => {
    const parsed = parseVideoUrl(url)
    if (!parsed) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: VIDEO_URL_ERRORS.UNSUPPORTED_PLATFORM,
      })
      return z.NEVER
    }
    return parsed
  })

/**
 * Zod schema for optional video URL
 * Returns ParsedVideoUrl if valid, undefined if empty
 */
export const optionalVideoUrlSchema = z
  .string()
  .optional()
  .nullable()
  .transform((url, ctx) => {
    // Allow empty/null values
    if (!url || url.trim() === "") {
      return undefined
    }

    // Validate URL format
    try {
      new URL(url)
    } catch {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: VIDEO_URL_ERRORS.INVALID_URL,
      })
      return z.NEVER
    }

    // Parse and validate platform
    const parsed = parseVideoUrl(url)
    if (!parsed) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: VIDEO_URL_ERRORS.UNSUPPORTED_PLATFORM,
      })
      return z.NEVER
    }

    return parsed
  })

/**
 * Simple string schema for video URL validation (returns string, not parsed object)
 * Use this when you just need to validate the URL but store the original string
 */
export const videoUrlStringSchema = z
  .string()
  .min(1, VIDEO_URL_ERRORS.EMPTY_URL)
  .url(VIDEO_URL_ERRORS.INVALID_URL)
  .refine((url) => isSupportedVideoUrl(url), {
    message: VIDEO_URL_ERRORS.UNSUPPORTED_PLATFORM,
  })

/**
 * Optional string schema for video URL validation
 * Returns the original string if valid, undefined if empty
 */
export const optionalVideoUrlStringSchema = z
  .string()
  .optional()
  .nullable()
  .transform((url, ctx) => {
    // Allow empty/null values
    if (!url || url.trim() === "") {
      return undefined
    }

    // Validate URL format
    try {
      new URL(url)
    } catch {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: VIDEO_URL_ERRORS.INVALID_URL,
      })
      return z.NEVER
    }

    // Validate it's from a supported platform
    if (!isSupportedVideoUrl(url)) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: VIDEO_URL_ERRORS.UNSUPPORTED_PLATFORM,
      })
      return z.NEVER
    }

    return url
  })

// Type exports
export type VideoUrlInput = z.input<typeof videoUrlSchema>
export type VideoUrlOutput = z.output<typeof videoUrlSchema>
export type OptionalVideoUrlOutput = z.output<typeof optionalVideoUrlSchema>

